/**
 * @param {number[]} nums1
 * @param {number[]} nums0
 * @return {number}
 */
function solve(nums1, nums0) {
    const MOD = 10**9 + 7;
    const n = nums1.length;
    const segments = [];

    for (let i = 0; i < n; i++) {
        const ones = nums1[i];
        const zeros = nums0[i];
        // Represent the segment as a value for comparison purposes.
        // A segment with more '1's relative to its length is "larger".
        // A simple way to compare is to use a custom comparison logic:
        // Segment A is greater than Segment B if it contributes more to the total value.
        // This is equivalent to comparing A || B vs B || A lexicographically.
        segments.push({
            ones: ones,
            zeros: zeros
        });
    }

    // Custom sorting comparator function:
    // Compare segment A (sA) and segment B (sB).
    // We want to place sA before sB if sA || sB > sB || sA lexicographically.
    // sA || sB is the concatenation of '1'*onesA + '0'*zerosA followed by '1'*onesB + '0'*zerosB.
    const comparator = (sA, sB) => {
        // String representation of sA followed by sB
        const ab_str = '1'.repeat(sA.ones) + '0'.repeat(sA.zeros) + '1'.repeat(sB.ones) + '0'.repeat(sB.zeros);
        // String representation of sB followed by sA
        const ba_str = '1'.repeat(sB.ones) + '0'.repeat(sB.zeros) + '1'.repeat(sA.ones) + '0'.repeat(sA.zeros);

        if (ab_str > ba_str) {
            return -1; // sA should come before sB (descending order based on lexicographical comparison)
        } else if (ab_str < ba_str) {
            return 1;  // sB should come before sA
        } else {
            return 0;
        }
    };

    // Sort the segments using the custom comparator
    segments.sort(comparator);

    let result = 0;
    let currentPowerOf2 = 1;
    let totalLength = 0;

    // Calculate the final value by concatenating the optimally ordered segments
    for (let i = 0; i < n; i++) {
        const segment = segments[i];
        const ones = segment.ones;
        const zeros = segment.zeros;
        const length = ones + zeros;

        // The current segment is placed at position (totalLength) to (totalLength + length - 1)
        // The value contributed by this segment is:
        // Sum_{j=0}^{ones-1} 2^(totalLength + zeros + (length - 1 - j))
        // where the position index is relative to the rightmost bit (0-indexed).
        // The leftmost bit of this segment is at position: totalLength + zeros + ones - 1
        // The rightmost bit of this segment is at position: totalLength

        // Contribution of the '1's:
        // For the i-th segment (in sorted order), the '1's are followed by 'zeros'.
        // The segment starts at a total length of totalLength.
        // The bits contributed by the '1's are at positions:
        // (totalLength + zeros) + (ones - 1), ..., (totalLength + zeros)
        // In terms of power of 2 (where 2^0 is the rightmost bit):
        // The rightmost '1' is at power: totalLength + zeros
        // The leftmost '1' is at power: totalLength + zeros + ones - 1

        // A simpler way:
        // The total length of the string built so far is `totalLength`.
        // The new segment of length `length` is appended.
        // The bits of the new segment will occupy positions from `totalLength` up to `totalLength + length - 1`.

        // The value added by this segment is (Value of '1'*ones) * 2^(zeros)
        // where Value of '1'*ones is (2^ones - 1) in base 2.

        // Value of '1'*ones = (2^ones - 1)
        // This is a string of 'ones' ones.
        // In base 10, this is 2^ones - 1.
        // We need to compute this modulo MOD.

        // Calculate (2^ones - 1) mod MOD
        let ones_value_mod = (power(2, ones, MOD) - 1 + MOD) % MOD;

        // Multiply by 2^zeros mod MOD
        // The zeros shift the value to the left by `zeros` positions.
        let contribution = (ones_value_mod * power(2, zeros, MOD)) % MOD;

        // Add to result
        result = (result + contribution) % MOD;

        totalLength += length;
    }

    return result;
}

/**
 * Computes (base^exp) % mod efficiently using binary exponentiation.
 * @param {number} base
 * @param {number} exp
 * @param {number} mod
 * @returns {number}
 */
function power(base, exp, mod) {
    let res = 1n;
    let b = BigInt(base);
    let e = BigInt(exp);
    let m = BigInt(mod);
    b %= m;

    while (e > 0n) {
        if (e % 2n === 1n) {
            res = (res * b) % m;
        }
        b = (b * b) % m;
        e /= 2n;
    }
    return Number(res);
}

