using namespace std;

// Define the structure to hold segment information
struct Segment {
    long long ones;
    long long zeros;
};

// Modular exponentiation function (a^b) % mod
long long power(long long base, long long exp, long long mod) {
    long long res = 1;
    base %= mod;
    while (exp > 0) {
        if (exp % 2 == 1) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return res;
}

class Solution {
public:
    long long solve(vector<long long> nums1, vector<long long> nums0) {
        const long long MOD = 1e9 + 7;
        int n = nums1.size();
        vector<Segment> segments(n);

        for (int i = 0; i < n; ++i) {
            segments[i] = {nums1[i], nums0[i]};
