        // Custom sorting comparator function:
        // Compare segment A (sA) and segment B (sB).
        // We want to place sA before sB if sA || sB > sB || sA lexicographically.
        auto comparator = [&](const Segment& sA, const Segment& sB) -> bool {
            // Concatenate A then B: '1'*onesA + '0'*zerosA + '1'*onesB + '0'*zerosB
            // Compare this with B then A: '1'*onesB + '0'*zerosB + '1'*onesA + '0'*zerosA

            // Since string manipulation can be slow, we compare based on lexicographical rules.
            // A binary string S is greater than T if at the first differing bit, S has 1 and T has 0.

            // Lexicographical comparison of AB vs BA:
            // The comparison must be done character by character based on the structure: 1...1 0...0

            // This is equivalent to comparing (onesA, zerosA) vs (onesB, zerosB) based on the greedy strategy:
            // A is preferred over B if (A || B) > (B || A) lexicographically.

            // Let A = 1...10...0 (onesA ones, zerosA zeros)
            // Let B = 1...10...0 (onesB ones, zerosB zeros)

            // We compare A followed by B vs B followed by A.

            // If onesA > onesB, A starts with more '1's, so AB > BA (A is preferred)
            if (sA.ones > sB.ones) return true;
            if (sA.ones < sB.ones) return false;

            // If ones are equal, compare zeros:
            // Case 1: zerosA > zerosB. 
            // A = 1...1 0...0 (zerosA zeros)
            // B = 1...1 0...0 (zerosB zeros)
            // If zerosA > zerosB, A has more trailing zeros. 
            // AB starts with onesA ones, zerosA zeros, followed by B.
            // BA starts with onesB ones, zerosB zeros, followed by A.

            // If onesA = onesB:
            // A = 1^k 0^za, B = 1^k 0^zb.
            // AB = 1^k 0^za 1^k 0^zb
            // BA = 1^k 0^zb 1^k 0^za

            // The first k bits are the same (1^k).
            // Next, compare 0^za vs 0^zb. This is complex because the next block is 1^k.

            // The correct greedy comparison for this type of problem (similar to largest number formed by concatenation) 
            // is to check which segment results in a lexicographically larger string when placed first.

            // A segment A contributes a value roughly proportional to 2^(onesA + zerosA - 1) * (2^onesA - 1) / 2^zerosA
            // A simpler metric derived from the lexicographical comparison:

            // Compare string A concatenated with B vs B concatenated with A.

            // Compare A_str + B_str vs B_str + A_str
            // A_str = string(onesA, '1') + string(zerosA, '0')
            // B_str = string(onesB, '1') + string(zerosB, '0')

            // Since direct string construction is too slow (total length up to 2*10^5), we simulate the comparison.

            // We check if A followed by B is lexicographically greater than B followed by A.

            // Compare A vs B based on how they start.
            // A starts with onesA ones. B starts with onesB ones.

            // If onesA > onesB, A is "more dominant" in leading ones, so A > B (A comes first)
            if (sA.ones != sB.ones) return sA.ones > sB.ones;

            // If onesA == onesB = k:
            // A = 1^k 0^za
            // B = 1^k 0^zb
            // AB starts with 1^k 0^za 1^k 0^zb
            // BA starts with 1^k 0^zb 1^k 0^za

            // The first k bits are equal. We compare the block starting at index k.
            // AB continues with 0^za. BA continues with 0^zb.
            if (sA.zeros != sB.zeros) {
                // If zerosA > zerosB, AB has a longer run of 0s immediately after the initial 1^k block, 
                // but BA will switch back to 1s sooner (after 0^zb).
                // Since '0' < '1', a longer run of '0's is better if the next character is '0', 
                // but here the next character after the 0-block is a '1' from the other segment.

                // If zerosA > zerosB:
                // AB: ... 0^za 1^k ...
                // BA: ... 0^zb 1^k ...
                // The difference occurs after 0^zb. At this point, AB has '0' (if za > zb), BA has '1'.
                // If za > zb, at position k+zb: AB has '0', BA has '1'. So BA > AB. A should NOT come before B.
                // If za < zb, at position k+za: AB has '1', BA has '0'. So AB > BA. A should come before B.

                if (sA.zeros > sB.zeros) return false; // AB < BA
                if (sA.zeros < sB.zeros) return true;  // AB > BA
            }

            // If onesA == onesB and zerosA == zerosB, they are equal.
            return false; 
        };

        // Sort the segments using the custom comparator
        sort(segments.begin(), segments.end(), comparator);

        long long result = 0;

        // Calculate the final value modulo MOD
        for (const auto& segment : segments) {
            long long ones = segment.ones;
            long long zeros = segment.zeros;

            // Contribution of '1'*ones followed by '0'*zeros.
            // The value of '1'*ones (as a pure number) is 2^ones - 1.
            // Since these '1's are followed by 'zeros' number of '0's, the value is multiplied by 2^zeros.
            // Contribution = (2^ones - 1) * 2^zeros mod MOD.

            // Calculate (2^ones - 1) mod MOD
            long long ones_value_mod = (power(2, ones, MOD) - 1 + MOD) % MOD;

            // Calculate 2^zeros mod MOD
            long long power_of_2_zeros = power(2, zeros, MOD);

            // Contribution = ones_value_mod * power_of_2_zeros mod MOD
            long long contribution = (ones_value_mod * power_of_2_zeros) % MOD;

            // Add to result
            result = (result + contribution) % MOD;
        }

        return result;
    }
};
